SELECT bands.name AS Band_Name, results.score AS Highest_Score
FROM results
INNER JOIN bands ON results.band_id = bands.band_id
WHERE results.event_id = 1 AND results.score = (
    SELECT MAX(score) FROM results WHERE event_id = 1
);

SELECT COUNT(DISTINCT b.band_id)
FROM bands b
JOIN event_bands eb ON b.band_id = eb.band_id;

SELECT COUNT(*) 
FROM event_bands 
WHERE band_id = 1;

SELECT c.status, COUNT(c.competition_id) AS total_competitions
FROM competitions c
GROUP BY c.status;

SELECT COUNT(band_id)
FROM bands
WHERE location = 'Los Angeles';
